const t = input.trim();
const hasStatusLine = /^HTTP\/[\d.]+ \d{3}/m.test(t);
const hasRequestLine = /^(GET|POST|PUT|DELETE|PATCH|HEAD|OPTIONS) .+ HTTP\/[\d.]+$/m.test(t);
const hasHeaderLines = (t.match(/^[\w-]+:\s*.+$/mg) || []).length >= 2;
return (hasStatusLine || hasRequestLine || hasHeaderLines) ? 0.95 : 0;

plugin.executeCode:
const KNOWN = {
  'content-type': 'Specifies the media type and encoding of the request/response body.',
  'content-length': 'Size of the response body in bytes.',
  'authorization': 'Credentials for authenticating the client with the server.',
  'cache-control': 'Directives for caching mechanisms (max-age, no-cache, no-store, etc.).',
  'content-encoding': 'Encoding applied to the body (gzip, br, deflate).',
  'accept': 'Media types the client can handle.',
  'accept-encoding': 'Compression algorithms the client supports.',
  'accept-language': 'Preferred natural language for the response.',
  'access-control-allow-origin': 'CORS: which origins may access the resource.',
  'access-control-allow-methods': 'CORS: permitted HTTP methods.',
  'access-control-allow-headers': 'CORS: permitted request headers.',
  'access-control-max-age': 'CORS: how long preflight results can be cached (seconds).',
  'strict-transport-security': 'HSTS: forces HTTPS for a specified max-age.',
  'x-content-type-options': 'Prevents MIME sniffing (nosniff).',
  'x-frame-options': 'Controls iframe embedding (DENY, SAMEORIGIN).',
  'x-xss-protection': 'Legacy XSS filter setting (mostly deprecated).',
  'content-security-policy': 'Restricts sources of scripts, styles, and other resources.',
  'referrer-policy': 'Controls how much referrer info is sent.',
  'permissions-policy': 'Restricts browser features (camera, microphone, etc.).',
  'etag': 'Unique identifier for a specific version of a resource (used for conditional requests).',
  'last-modified': 'Date/time the resource was last changed.',
  'expires': 'Date/time after which the response is stale.',
  'set-cookie': 'Instructs the client to store a cookie.',
  'cookie': 'Sends stored cookies back to the server.',
  'location': 'Redirect target URL (used with 3xx responses).',
  'server': 'Software the server is running (may be suppressed for security).',
  'transfer-encoding': 'Encoding used to transfer the body (chunked, identity).',
  'vary': 'Tells caches which request headers affect the response.',
  'connection': 'Controls whether the connection stays open after the request.',
  'host': 'Domain name and port of the server being requested.',
  'user-agent': 'Client software making the request.',
  'origin': 'Origin of the request (used in CORS).',
  'x-request-id': 'Unique identifier for tracing a request across services.',
  'x-forwarded-for': 'Original IP address of a client going through proxies.',
  'x-forwarded-proto': 'Protocol (HTTP/HTTPS) used by the client before hitting a proxy.',
};

const lines = input.split('\n');
const output = [];
for (const raw of lines) {
  const line = raw.trimEnd();
  if (!line) { output.push(''); continue; }
  // Status or request line
  if (/^HTTP\//.test(line) || /^(GET|POST|PUT|DELETE|PATCH|HEAD|OPTIONS)\s/.test(line)) {
    output.push('>>> ' + line);
    continue;
  }
  const colon = line.indexOf(':');
  if (colon === -1) { output.push(line); continue; }
  const name = line.slice(0, colon).trim();
  const value = line.slice(colon + 1).trim();
  const explanation = KNOWN[name.toLowerCase()] || '';
  output.push(`${name}: ${value}`);
  if (explanation) output.push(`  ^ ${explanation}`);
}
return { output: output.join('\n'), outputLanguage: 'text' };
